const baseScript = doc.createElement('script');
baseScript.textContent = `
    window.IS_CONDUIT_PREVIEW = true;
    window.process = { env: { NODE_ENV: 'development' } };

    const safeStringify = (obj) => {
        const cache = new Set();
        return JSON.stringify(obj, (key, value) => {
            if (typeof value === 'object' && value !== null) {
                if (cache.has(value)) return '[Circular]';
                cache.add(value);
            }
            if (value instanceof HTMLElement) return value.outerHTML.substring(0, 100) + '...';
            return value;
        }, 2);
    };

    ['log', 'warn', 'error', 'debug', 'info'].forEach(method => {
        const original = console[method];
        console[method] = (...args) => {
            window.parent.postMessage({ 
                type: 'CONDUIT_LOG', 
                method, 
                args: args.map(a => typeof a === 'object' ? JSON.parse(safeStringify(a)) : a),
                time: new Date().toLocaleTimeString([], {hour12:false, hour:'2-digit', minute:'2-digit', second:'2-digit'})
            }, '*');
            original.apply(console, args);
        };
    });

    const originalFetch = window.fetch;
    window.fetch = async (...args) => {
        const start = Date.now();
        const url = args[0];
        const options = args[1] || {};
        try {
            const response = await originalFetch(...args);
            const clone = response.clone();
            const duration = Date.now() - start;
            let resBody = '[Binary Data]';
            try { resBody = await clone.json(); } catch(e) { try { resBody = await clone.text(); } catch(e2){} }

            window.parent.postMessage({
                type: 'CONDUIT_NETWORK',
                payload: {
                    url, method: options.method || 'GET',
                    status: response.status, duration,
                    requestBody: options.body || null,
                    responseBody: resBody
                }
            }, '*');
            return response;
        } catch(err) {
            window.parent.postMessage({ type: 'CONDUIT_LOG', method: 'error', args: ['Fetch Failed: ' + url, err.message], time: '' }, '*');
            throw err;
        }
    };
`;
doc.head.prepend(baseScript);

