        method: 'POST', headers: {'Content-Type': 'application/json'},
        body: apiBody({ action: 'fetch_tree', project_path: effectiveRoot, ref_sha: sha })
    });
    const treeData = await treeRes.json();

    // Detect if backend is prefixing paths with Repo Name (Common in some git checkouts)
    const repoPrefix = CONFIG.repoName + '/';
    const hasRepoPrefix = treeData.files && treeData.files.length > 0 && treeData.files.every(f => f.path.startsWith(repoPrefix));

    const files = (treeData.files || []).filter(f => f.path.startsWith(effectiveRoot) || (hasRepoPrefix && f.path.startsWith(repoPrefix + effectiveRoot)));

    console.log(`📦 [Bundler] Prefix Detection: hasRepoPrefix=${hasRepoPrefix}, root=${effectiveRoot}`);

